    protected override async Task OnInitializedAsync()
    {
        if (IsCreate)
        {
            // Auto-populate defaults for new receipt
            Model.ReceiptNo = $"RCP-{Guid.NewGuid().ToString("N")[..6].ToUpperInvariant()}";
