                Navigation.NavigateTo("/receipts/list");
            }
        }
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        try
        {
            bool ok;
            if (IsCreate)
            {
                ok = await ReceiptService.CreateReceiptAsync(Model);
            }
            else
