                Navigation.NavigateTo("/receipts/list");
            }
            else
            {
                await ToastService.ShowErrorAsync("Failed to save receipt.");
            }
        }
        catch (Exception ex)
        {
            await ToastService.ShowErrorAsync($"Save failed: {ex.Message}");
        }
        finally
        {
            IsSaving = false;
        }
    }

